import React, { useState, useEffect, useMemo, useRef } from 'react';
import axios from 'axios';

function App() {
  // --- СОСТОЯНИЕ ---
  const [activePage, setActivePage] = useState('market'); // 'market' или 'portfolio'
  const [walletBalance, setWalletBalance] = useState(10000);
  const [holdings, setHoldings] = useState([]);
  const [marketPrices, setMarketPrices] = useState({
    'DEV': { price: 150.00, direction: 'neutral' },
    'PEX': { price: 280.50, direction: 'neutral' },
    'AI': { price: 420.00, direction: 'neutral' }
  });
  
  const [token] = useState("YOUR_JWT_TOKEN_HERE");

  // --- WEB SOCKET (РЕАЛЬНОЕ ВРЕМЯ) ---
  useEffect(() => {
    const ws = new WebSocket('ws://localhost:5000', token);

    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
      if (data.type === "TICKER_UPDATE") {
        setMarketPrices(prev => {
          const oldPrice = prev[data.payload.ticker]?.price || 0;
          const newPrice = data.payload.price;
          
          // Определяем направление движения цены для анимации
          const direction = newPrice > oldPrice ? 'up' : newPrice < oldPrice ? 'down' : 'neutral';
          
          return {
            ...prev,
            [data.payload.ticker]: { price: newPrice, direction }
          };
        });
      }
    };

    return () => ws.close();
  }, [token]);

  // --- РАСЧЕТ КАПИТАЛА (VIRTUAL NET WORTH) ---
  const netWorth = useMemo(() => {
    const assetsValue = holdings.reduce((total, stock) => {
      const currentPrice = marketPrices[stock.ticker]?.price || 0;
      return total + (stock.amount * currentPrice);
    }, 0);
    return walletBalance + assetsValue;
  }, [walletBalance, holdings, marketPrices]);

  // --- ЛОГИКА ПОКУПКИ ---
  const handleBuy = async (ticker) => {
    try {
      const response = await axios.post('http://localhost:5000/api/buy', 
        { ticker, amount: 1 }, 
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setWalletBalance(response.data.balance);
      setHoldings(response.data.holdings);
    } catch (error) {
      alert("Недостаточно средств или ошибка сети.");
    }
  };

  // --- СТИЛИ ИНДИКАТОРОВ ---
  const getPriceStyle = (direction) => ({
    fontSize: '1.8rem',
    fontWeight: 'bold',
    transition: 'all 0.3s ease',
    color: direction === 'up' ? '#2ecc71' : direction === 'down' ? '#e74c3c' : '#2c3e50',
    backgroundColor: direction === 'up' ? 'rgba(46, 204, 113, 0.1)' : direction === 'down' ? 'rgba(231, 76, 60, 0.1)' : 'transparent',
    padding: '5px',
    borderRadius: '5px'
  });

  return (
    <div style={styles.container}>
      {/* ПАНЕЛЬ УПРАВЛЕНИЯ (ВСЕГДА ВИДНА) */}
      <header style={styles.header}>
        <div>
          <h1 style={{ margin: 0 }}>PEX Terminal</h1>
          <p style={{ color: '#7f8c8d' }}>Инвестируй в людей как в компании</p>
        </div>
        <div style={styles.statsContainer}>
          <div style={styles.statBox}>
            <span style={styles.label}>CASH</span>
            <span style={styles.value}>${walletBalance.toFixed(2)}</span>
          </div>
          <div style={styles.statBox}>
            <span style={styles.label}>NET WORTH</span>
            <span style={{ ...styles.value, color: '#3498db' }}>${netWorth.toFixed(2)}</span>
          </div>
        </div>
      </header>

      {/* НАВИГАЦИЯ МЕЖДУ СТРАНИЦАМИ */}
      <nav style={styles.navbar}>
        <button 
          onClick={() => setActivePage('market')} 
          style={activePage === 'market' ? styles.navBtnActive : styles.navBtn}>
          📊 Рынок (Live)
        </button>
        <button 
          onClick={() => setActivePage('portfolio')} 
          style={activePage === 'portfolio' ? styles.navBtnActive : styles.navBtn}>
          💼 Мой Портфель
        </button>
      </nav>

      <main style={styles.content}>
        {/* СТРАНИЦА 1: КУРСЫ И ПОКУПКА */}
        {activePage === 'market' && (
          <section>
            <h2 style={styles.pageTitle}>Биржевые котировки</h2>
            <div style={styles.grid}>
              {Object.entries(marketPrices).map(([ticker, data]) => (
                <div key={ticker} style={styles.marketCard}>
                  <div style={styles.cardBadge}>LIVE</div>
                  <h3 style={{ fontSize: '1.5rem', marginBottom: '5px' }}>${ticker}</h3>
                  <div style={getPriceStyle(data.direction)}>
                    ${data.price.toFixed(2)}
                    <span style={{ fontSize: '0.8rem', marginLeft: '5px' }}>
                      {data.direction === 'up' ? '▲' : data.direction === 'down' ? '▼' : ''}
                    </span>
                  </div>
                  <button onClick={() => handleBuy(ticker)} style={styles.buyButton}>
                    Купить акцию
                  </button>
                </div>
              ))}
            </div>
          </section>
        )}

        {/* СТРАНИЦА 2: ПОРТФЕЛЬ И АКТИВЫ */}
        {activePage === 'portfolio' && (
          <section style={styles.portfolioSection}>
            <h2 style={styles.pageTitle}>Ваши инвестиции</h2>
            {holdings.length === 0 ? (
              <div style={styles.emptyState}>У вас пока нет купленных акций. Перейдите на рынок, чтобы начать.</div>
            ) : (
              <div style={styles.tableWrapper}>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      <th>Тикер</th>
                      <th>Кол-во</th>
                      <th>Тек. цена</th>
                      <th>Всего</th>
                    </tr>
                  </thead>
                  <tbody>
                    {holdings.map(h => {
                      const currentPrice = marketPrices[h.ticker]?.price || 0;
                      return (
                        <tr key={h.ticker}>
                          <td style={{ fontWeight: 'bold' }}>${h.ticker}</td>
                          <td>{h.amount}</td>
                          <td>${currentPrice.toFixed(2)}</td>
                          <td style={{ color: '#2ecc71', fontWeight: 'bold' }}>
                            ${(h.amount * currentPrice).toFixed(2)}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </section>
        )}
      </main>
    </div>
  );
}

